configfiles.configfile:
import json

images = {"raw": [], "label": []}

#for $img in $rep_images
image_type = "${img.input_image_type}"
zarr_name = "${img.input_image.metadata.store_root}"
metadata_path = "${img.input_metadata}"

with open(metadata_path) as md_file:
    md = json.load(md_file)

images[image_type].append({
    "path": zarr_name,
    "md": md
})
#end for

clean_dict = {}
for key, value in images.items():
    if value:
        clean_dict[key] = value
images = clean_dict

with open("images.json", "w") as file:
    json.dump(images, file)

import json

options = {}

if "${spatial}":
    options["spatial:"] = "${spatial}"
if "${matrix}":
    options["matrix:"] = "${matrix}"

with open("options.json", "w") as file:
    json.dump(options, file)
